class Solution:
    def coinChange(self, coins, amount):
        from collections import deque
        if amount == 0:
            return 0
        seen = [False] * (amount + 1)
        seen[0] = True
        q = deque([(0, 0)])
        while q:
            cur, steps = q.popleft()
            for c in coins:
                nxt = cur + c
                if nxt == amount:
                    return steps + 1
                if nxt < amount and not seen[nxt]:
                    seen[nxt] = True
                    q.append((nxt, steps + 1))
        return -1

